// Compile all Salesforce results into a weekly CS digest
// The merge node combines all 4 query results into a flat array
// We need to identify which items came from which query

const allItems = $input.all().map(i => i.json);

// Separate data by presence of distinguishing fields
const churns = allItems.filter(i => i.StageName === 'Closed Lost');
const renewals = allItems.filter(i => i.StageName && i.StageName !== 'Closed Lost' && i.CloseDate);
const cases = allItems.filter(i => i.Subject !== undefined && i.Priority !== undefined);
const stale = allItems.filter(i => i.LastActivityDate !== undefined && !i.Subject && !i.StageName);

const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

// Build Slack Block Kit message
const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `📊 CS Weekly Digest — ${today}`, emoji: true }
  },
  { type: 'divider' }
];

// Section 1: Churns
blocks.push({
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: churns.length > 0
      ? `*💔 New Churns This Week (${churns.length})*\n` +
        churns.map(c => `• ${c['Account.Name'] || c.Account?.Name} — $${Number(c.Amount || 0).toLocaleString()} (CSM: ${c['Owner.Name'] || c.Owner?.Name})`).join('\n')
      : '*💚 No New Churns This Week*'
  }
});
blocks.push({ type: 'divider' });

// Section 2: Renewals Due Soon
blocks.push({
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: renewals.length > 0
      ? `*🔄 Renewals Closing This Week (${renewals.length})*\n` +
        renewals.map(r => `• ${r['Account.Name'] || r.Account?.Name} — $${Number(r.Amount || 0).toLocaleString()} — ${r.CloseDate} (${r.StageName})`).join('\n')
      : '*🔄 No Renewals Due This Week*'
  }
});
blocks.push({ type: 'divider' });

// Section 3: Escalated Cases
blocks.push({
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: cases.length > 0
      ? `*🚨 High-Priority Open Cases (${cases.length})*\n` +
        cases.map(c => `• ${c['Account.Name'] || c.Account?.Name}: ${c.Subject} (${c.Status})`).join('\n')
      : '*✅ No High-Priority Open Cases*'
  }
});
blocks.push({ type: 'divider' });

// Section 4: Stale Accounts
blocks.push({
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: stale.length > 0
      ? `*⚠️ Accounts With No Activity (21+ days, top ${stale.length})*\n` +
        stale.map(a => {
          const days = a.LastActivityDate
            ? Math.floor((Date.now() - new Date(a.LastActivityDate).getTime()) / 86400000)
            : 'N/A';
          return `• ${a.Name} — last activity: ${days}d ago (CSM: ${a['Owner.Name'] || a.Owner?.Name})`;
        }).join('\n')
      : '*✅ All Accounts Have Recent Activity*'
  }
});

blocks.push({ type: 'divider' });
blocks.push({
  type: 'context',
  elements: [{
    type: 'mrkdwn',
    text: `_Generated by n8n Weekly CS Digest | ${new Date().toISOString()}_`
  }]
});

return [{ json: { blocks, text: `CS Weekly Digest — ${today}` } }];
